import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Co-Leader Guide","description":"","frontmatter":{},"headers":[],"relativePath":"roles/co-leader.md","filePath":"roles/co-leader.md"}'),l={name:"roles/co-leader.md"};function i(n,e,s,d,h,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="co-leader-guide" tabindex="-1">Co-Leader Guide <a class="header-anchor" href="#co-leader-guide" aria-label="Permalink to &quot;Co-Leader Guide&quot;">​</a></h1><p>This is the <strong>start here</strong> guide for <code>Co-Leader</code> users. The single most important thing to know is simple:</p><h2 id="you-help-run-the-alliance-but-you-do-not-get-the-delete-buttons" tabindex="-1">You help run the alliance, but you do not get the delete buttons <a class="header-anchor" href="#you-help-run-the-alliance-but-you-do-not-get-the-delete-buttons" aria-label="Permalink to &quot;You help run the alliance, but you do not get the delete buttons&quot;">​</a></h2><p>Co-Leaders can do a lot of hands-on work, but <strong>cannot delete</strong> things.</p><p>That means:</p><ul><li>you can add and edit players</li><li>you can enter results</li><li>you can upload and review imports</li><li>you can use analytics and reports</li><li>you cannot delete players</li><li>you cannot delete events</li><li>you cannot delete imports</li><li>you cannot use restore or recycle-bin actions</li></ul><p>If you need a deletion, rollback, restore, or other risky action, that usually belongs to the <code>Alliance Leader</code>, <code>King</code>, or <code>Supreme Admin</code>.</p><h2 id="your-main-reading-path" tabindex="-1">Your main reading path <a class="header-anchor" href="#your-main-reading-path" aria-label="Permalink to &quot;Your main reading path&quot;">​</a></h2><p>Start with:</p><ol><li><a href="./../how-to/my-alliance.html">Use the My Alliance Page</a></li><li><a href="./../how-to/players-directory.html">Players Directory</a></li><li><a href="./../how-to/add-player.html">Add a Player</a></li><li><a href="./../how-to/edit-player.html">Edit Player Details</a></li><li><a href="./../how-to/manual-input.html">Enter Results Manually</a></li><li><a href="./../imports/overview.html">How Screenshot Imports Work</a></li></ol><p>Then add:</p><ul><li><a href="./../imports/review-rows.html">Review Import Rows</a></li><li><a href="./../imports/apply-import.html">Accept Rows (Apply an Import)</a></li><li><a href="./../analytics/overview.html">Analytics Overview</a></li><li><a href="./../analytics/player-cross-event.html">Player Cross-Event Analytics</a></li><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li></ul><h2 id="premium-and-grants" tabindex="-1">Premium and grants <a class="header-anchor" href="#premium-and-grants" aria-label="Permalink to &quot;Premium and grants&quot;">​</a></h2><p>Co-Leaders can help with alliance-side premium offers too.</p><p>Read:</p><ul><li><a href="./../subscriptions/accept-grant.html">Accept a Premium Offer</a></li><li><a href="./../subscriptions/premium-features.html">Premium Features</a></li></ul><p>Like Alliance Leaders, Co-Leaders only see the Kingdom analytics tab through an <strong>accepted</strong> grant that includes the kingdom analytics sharing feature.</p><h2 id="what-only-leaders-can-do-above-you" tabindex="-1">What only Leaders can do above you <a class="header-anchor" href="#what-only-leaders-can-do-above-you" aria-label="Permalink to &quot;What only Leaders can do above you&quot;">​</a></h2><p>The clearest differences are:</p><ul><li>deleting and restoring important records</li><li>managing certain settings</li><li>deeper subscription decisions for the alliance</li></ul><p>If you are unsure whether an action is meant for you, the app usually makes that clear by hiding the button or refusing the page.</p>',21)])])}const m=a(l,[["render",i]]);export{p as __pageData,m as default};
